
-- Migrated 2219 inventory transactions

COMMIT;

-- ============================================
-- POST-MIGRATION UPDATES
-- ============================================

-- Update order totals based on order_items
UPDATE orders o
SET 
    total_amount = COALESCE(sub.total, 0),
    items_count = COALESCE(sub.count, 0),
    items = COALESCE(sub.items_json, '[]'::jsonb)
FROM (
    SELECT 
        order_id, 
        SUM(total_price) as total,
        COUNT(*) as count,
        jsonb_agg(jsonb_build_object(
            'product_id', product_id,
            'product_name', product_name,
            'quantity', quantity,
            'unit_price', unit_price,
            'total_price', total_price
        )) as items_json
    FROM order_items 
    GROUP BY order_id
) sub
WHERE o.id = sub.order_id;

-- Update product stock based on inventory_transactions
UPDATE products p
SET stock = COALESCE(sub.total_qty, 0)
FROM (
    SELECT product_id, SUM(quantity) as total_qty
    FROM inventory_transactions
    GROUP BY product_id
) sub
WHERE p.id = sub.product_id;